import{_ as t,o,c as i,au as a}from"./chunks/framework.Bpqx6pAq.js";const p=JSON.parse('{"title":"Service hooks","description":"","frontmatter":{},"headers":[],"relativePath":"api/core/hooks/hooks.service.md","filePath":"api/core/hooks/hooks.service.md"}'),r={name:"api/core/hooks/hooks.service.md"};function n(d,e,c,s,h,l){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="service-hooks" tabindex="-1">Service hooks <a class="header-anchor" href="#service-hooks" aria-label="Permalink to &quot;Service hooks&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Hooks for controlling service-level behaviour: suppressing real-time events, rate limiting, and resource quota enforcement.</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="skipevents-hook" tabindex="-1"><code>skipEvents(hook)</code> <a class="header-anchor" href="#skipevents-hook" aria-label="Permalink to &quot;`skipEvents(hook)`&quot;">​</a></h3><p>Suppresses the real-time event normally emitted by a service method by setting <code>hook.event = null</code>. Useful when a service operation should not trigger client-side reactivity.</p><hr><h3 id="ratelimit-options" tabindex="-1"><code>rateLimit(options)</code> <a class="header-anchor" href="#ratelimit-options" aria-label="Permalink to &quot;`rateLimit(options)`&quot;">​</a></h3><blockquote><p>To be used as a <code>before</code> hook. Returns a hook function.</p></blockquote><p>Rate-limits calls to a service (and optionally a specific operation) using the <a href="https://en.wikipedia.org/wiki/Token_bucket" target="_blank" rel="noreferrer">token bucket algorithm</a>. Throws <code>TooManyRequests</code> when the token bucket is exhausted.</p><h4 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Option</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>tokensPerInterval</code></td><td>number</td><td>Number of allowed requests per interval</td></tr><tr><td><code>interval</code></td><td>number | string</td><td>Interval duration (ms or a string like <code>&#39;second&#39;</code>)</td></tr><tr><td><code>operation</code></td><td>string <em>(optional)</em></td><td>Restrict rate limiting to a specific method (e.g. <code>&#39;create&#39;</code>)</td></tr><tr><td><code>service</code></td><td>string <em>(optional)</em></td><td>Restrict rate limiting to a specific service name (useful as an app-level hook)</td></tr></tbody></table><hr><h3 id="countlimit-options" tabindex="-1"><code>countLimit(options)</code> <a class="header-anchor" href="#countlimit-options" aria-label="Permalink to &quot;`countLimit(options)`&quot;">​</a></h3><blockquote><p>To be used as a <code>before</code> hook. Returns a hook function.</p></blockquote><p>Enforces a maximum number of existing resources before allowing a new one to be created. Throws <code>Forbidden</code> when the quota is exceeded. A value of <code>-1</code> for <code>max</code> disables the limit.</p><h4 id="options-1" tabindex="-1">Options <a class="header-anchor" href="#options-1" aria-label="Permalink to &quot;Options&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Option</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>max</code></td><td>number | Function</td><td>Maximum allowed count, or an async function <code>(hook) =&gt; number</code></td></tr><tr><td><code>service</code></td><td>string | Function</td><td>Target service name or async function <code>(hook) =&gt; service</code> used to count existing items</td></tr><tr><td><code>query</code></td><td>Object | Function</td><td>Query applied when counting, or a function <code>(hook) =&gt; query</code></td></tr><tr><td><code>count</code></td><td>Function <em>(optional)</em></td><td>Custom async count function <code>(hook) =&gt; number</code> replacing the built-in service find</td></tr></tbody></table>',18)])])}const m=t(r,[["render",n]]);export{p as __pageData,m as default};
